mapper.select:
select r.roadway,a.drilling_location,a.group_no,a.borehole_no,a.borehole_code,a.borehole_length as borehole_length,r.id AS roadwayId,purpose_borehole,p.* from
t_drainage_parameter p
LEFT JOIN t_bk_act_borehole_info a ON p.borehole_id=a.id
LEFT JOIN t_roadway r ON r.id=a.roadway_id
LEFT JOIN t_purpose_borehole pb ON pb.id = a.purpose_borehole_id
WHERE
1=1

    AND a.roadway_id=#{roadwayId}


 AND a.group_no IN

        #{item}


 AND a.purpose_borehole_id IN

        #{item}


 AND a.borehole_no IN

        #{item}



    AND p.measure_date BETWEEN #{startdate} and #{enddate}

select g.id,a.borehole_no,g.gas_concentration,g.negative_pressure,g.measurer, g.measure_date, p.purpose_borehole,a.azimuth_angle as azimuth_angle,a.angle as angle, a.inclination_angle inclination_angle,a.borehole_length as borehole_length, f.see_rock_case,f.see_coal_case,n.navigation_point_name,a.distance_to_navigation_point,t.hole_seal_type, a.actual_coal_amount_flushed,g.borehole_id, g.beginningcon, g.create_by, g.create_time, g.update_by, g.update_time, g.remark from t_drainage_parameter g LEFT JOIN t_bk_act_borehole_info a ON a.id =g.borehole_id LEFT JOIN t_purpose_borehole p ON a.purpose_borehole_id=p.id LEFT JOIN t_roadway r ON r.id =a.roadway_id LEFT JOIN t_actual_flushing f ON f.borehole_id=a.id LEFT JOIN t_navigation_point n ON a.navigation_point_id=n.id LEFT JOIN t_holeseal_type t ON a.holeseal_type_id=t.id LEFT JOIN t_actual_flushing af ON a.id=af.borehole_id where beginningcon =false and gas_concentration > #{low} and gas_concentration < #{height} AND a.roadway_id IN
#{item}
AND a.purpose_borehole_id IN
#{item}
AND a.group_no IN
#{item}
AND a.borehole_no IN
#{item}
GROUP BY g.borehole_id ORDER BY g.measure_date DESC

select g.id,a.borehole_no,g.gas_concentration,g.negative_pressure,g.measurer, g.measure_date, p.purpose_borehole,a.azimuth_angle as azimuth_angle,a.angle as angle, a.inclination_angle as inclination_angle,a.borehole_length as borehole_length, a.see_rock_coal_case,n.navigation_point_name,a.distance_to_navigation_point,t.hole_seal_type, a.actual_coal_amount_flushed,g.borehole_id, g.beginningcon, g.create_by, g.create_time, g.update_by, g.update_time, g.remark from t_drainage_parameter g LEFT JOIN t_bk_act_borehole_info a ON a.id =g.borehole_id LEFT JOIN t_purpose_borehole p ON a.purpose_borehole_id=p.id LEFT JOIN t_roadway r ON r.id =a.roadway_id LEFT JOIN t_navigation_point n ON a.navigation_point_id=n.id LEFT JOIN t_holeseal_type t ON a.holeseal_type_id=t.id where beginningcon =true and gas_concentration > #{low} and gas_concentration < #{height} AND a.roadway_id IN
#{item}
AND a.purpose_borehole_id IN
#{item}
AND a.group_no IN
#{item}
AND a.borehole_no IN
#{item}
GROUP BY g.borehole_id ORDER BY g.measure_date DESC
